import "./alert.css";

import { cn } from "tailwind-variants";

import { AlertContext } from "./alert.context";
import { alertVariants, type AlertVariants } from "./alert.variants";

export type AlertRootProps = AlertVariants & React.ComponentProps<"div">;

export const AlertRoot = ({ children, className, variant, ...props }: AlertRootProps) => {
  const slots = alertVariants({ variant });

  return (
    <AlertContext value={{ slots }}>
      <div className={cn(slots.root(), className)} role="alert" {...props}>
        {children}
      </div>
    </AlertContext>
  );
};

import { cn } from "tailwind-variants";

import { useAlertContext } from "./alert.context";

export type AlertTitleProps = React.ComponentProps<"h5">;

export const AlertTitle = ({ children, className, ...props }: AlertTitleProps) => {
  const { slots } = useAlertContext();
  return (
    <h5 className={cn(slots.title(), className)} {...props}>
      {children}
    </h5>
  );
};

import { cn } from "tailwind-variants";

import { useAlertContext } from "./alert.context";

export type AlertDescriptionProps = React.ComponentProps<"div">;

export const AlertDescription = ({ children, className, ...props }: AlertDescriptionProps) => {
  const { slots } = useAlertContext();
  return (
    <div className={cn(slots.description(), className)} {...props}>
      {children}
    </div>
  );
};

import { createContext, useContext } from "react";

import { alertVariants } from "./alert.variants";

export type AlertContext = {
  slots: ReturnType<typeof alertVariants>;
};

export const AlertContext = createContext<AlertContext | null>(null);

export const useAlertContext = () => {
  const context = useContext(AlertContext);
  if (!context) {
    throw new Error("useAlertContext must be used within an Alert.Root");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const alertVariants = tv({
  slots: {
    root: "alert",
    title: "alert__title",
    description: "alert__description",
  },
  variants: {
    variant: {
      default: { root: "alert--default" },
      destructive: { root: "alert--destructive" },
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

export type AlertVariants = VariantProps<typeof alertVariants>;

.alert {
  @apply relative w-full rounded-lg border px-4 py-3 text-sm [&>svg+div]:translate-y-[-3px] [&>svg]:absolute [&>svg]:top-4 [&>svg]:left-4 [&>svg~*]:pl-7;
}

.alert--default {
  @apply bg-background text-foreground;
}

.alert--destructive {
  @apply border-destructive/50 text-destructive [&>svg]:text-destructive;
}

.alert__title {
  @apply mb-1 font-medium leading-none tracking-tight;
}

.alert__description {
  @apply text-sm [&_p]:leading-relaxed;
}

import { AlertDescription } from "./alert-description";
import { AlertRoot } from "./alert-root";
import { AlertTitle } from "./alert-title";

export const Alert = {
  Description: AlertDescription,
  Root: AlertRoot,
  Title: AlertTitle,
};

export { AlertDescription, AlertRoot, AlertTitle };

export { AlertContext, useAlertContext } from "./alert.context";

export { type AlertVariants, alertVariants } from "./alert.variants";
